"use client"

import { useEffect, useRef } from "react"
import { X, Calendar } from "lucide-react"

interface CalendlyModalProps {
  url: string
  isOpen: boolean
  onClose: () => void
}

export function CalendlyModal({ url, isOpen, onClose }: CalendlyModalProps) {
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (isOpen) {
      const script = document.createElement("script")
      script.src = "https://assets.calendly.com/assets/external/widget.js"
      script.async = true
      if (!document.querySelector('script[src*="calendly"]')) {
        document.body.appendChild(script)
      }
    }
  }, [isOpen])

  useEffect(() => {
    if (isOpen && containerRef.current) {
      containerRef.current.innerHTML = ""
      const widgetDiv = document.createElement("div")
      widgetDiv.className = "calendly-inline-widget"
      widgetDiv.setAttribute("data-url", url)
      widgetDiv.style.minWidth = "320px"
      widgetDiv.style.height = "600px"
      containerRef.current.appendChild(widgetDiv)
      
      const script = document.createElement("script")
      script.src = "https://assets.calendly.com/assets/external/widget.js"
      script.async = true
      containerRef.current.appendChild(script)
    }
  }, [isOpen, url])

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative bg-background rounded-xl shadow-2xl w-full max-w-3xl mx-4 max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between px-6 py-4 border-b border-border shrink-0">
          <div className="flex items-center gap-3">
            <Calendar className="w-5 h-5 text-primary" />
            <h2 className="text-lg font-semibold">Schedule a Consultation</h2>
          </div>
          <button
            onClick={onClose}
            className="text-muted-foreground hover:text-foreground transition-colors p-1"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
        <div className="flex-1 overflow-auto p-4 bg-background">
          <div ref={containerRef} className="calendly-container" />
        </div>
      </div>
    </div>
  )
}
