"use client"

import { useState } from "react"
import { ChevronLeft, ChevronRight, ExternalLink, Github } from "lucide-react"
import Link from "next/link"

interface Project {
  name: string
  description: string
  language: string
  languageColor: string
  url: string
  demo: string
  hasDemo: boolean
  logo: string
}

interface Category {
  name: string
  icon: any
  color: string
  projects: Project[]
}

interface OpenSourceTabsProps {
  categories: Category[]
}

function ProjectDemo({ project }: { project: Project }) {
  if (!project.demo) return null

  return (
    <div className="w-full">
      <div className="rounded-t-lg border border-b-0 border-border bg-muted/30 overflow-hidden">
        <div className="h-10 flex items-center px-4 gap-2 border-b border-border">
          <div className="w-3 h-3 rounded-full bg-red-400" />
          <div className="w-3 h-3 rounded-full bg-yellow-400" />
          <div className="w-3 h-3 rounded-full bg-green-400" />
          <span className="ml-2 text-xs font-mono text-muted-foreground truncate">
            {project.demo.replace("https://", "")}
          </span>
        </div>
      </div>
      <iframe
        src={project.demo}
        className="w-full h-[70vh] border border-t-0 border-border rounded-b-lg"
        title={`${project.name} demo`}
        loading="eager"
        sandbox="allow-scripts allow-same-origin allow-popups allow-forms allow-same-origin-ancestors"
      />
    </div>
  )
}

function ProjectCarousel({ category }: { category: Category }) {
  const [currentIndex, setCurrentIndex] = useState(0)
  const projects = category.projects

  const goNext = () => {
    setCurrentIndex((prev) => (prev + 1) % projects.length)
  }

  const goPrev = () => {
    setCurrentIndex((prev) => (prev - 1 + projects.length) % projects.length)
  }

  if (projects.length === 1) {
    const project = projects[0]
    return (
      <div className="w-full">
        <div className="mb-6 flex items-center gap-4">
          <div className="w-16 h-16 rounded-xl bg-white border border-border shadow-sm flex items-center justify-center">
            <img
              src={project.logo || `/logos/${project.name.toLowerCase()}-logo.png`}
              alt={project.name}
              className="w-12 h-12 object-contain"
            />
          </div>
          <div>
            <h3 className="text-xl font-bold text-foreground">{project.name}</h3>
            <span className={`text-sm font-mono ${project.languageColor}`}>{project.language}</span>
          </div>
          <div className="ml-auto flex gap-2">
            <a
              href={project.demo}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-700 transition-colors"
            >
              <ExternalLink className="w-4 h-4" />
              Open App
            </a>
            <a
              href={project.url}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-2 border border-border px-4 py-2 rounded-lg font-medium hover:bg-muted transition-colors"
            >
              <Github className="w-4 h-4" />
              Source
            </a>
          </div>
        </div>
        <p className="text-muted-foreground mb-6">{project.description}</p>
        <ProjectDemo project={project} />
      </div>
    )
  }

  return (
    <div className="w-full">
      <div className="mb-6 flex items-center gap-4">
        <div className="w-16 h-16 rounded-xl bg-white border border-border shadow-sm flex items-center justify-center">
          <img
            src={projects[currentIndex].logo || `/logos/${projects[currentIndex].name.toLowerCase()}-logo.png`}
            alt={projects[currentIndex].name}
            className="w-12 h-12 object-contain"
          />
        </div>
        <div>
          <h3 className="text-xl font-bold text-foreground">{projects[currentIndex].name}</h3>
          <span className={`text-sm font-mono ${projects[currentIndex].languageColor}`}>{projects[currentIndex].language}</span>
        </div>
        <div className="ml-auto flex gap-2">
          <a
            href={projects[currentIndex].demo}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-700 transition-colors"
          >
            <ExternalLink className="w-4 h-4" />
            Open App
          </a>
          <a
            href={projects[currentIndex].url}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center gap-2 border border-border px-4 py-2 rounded-lg font-medium hover:bg-muted transition-colors"
          >
            <Github className="w-4 h-4" />
            Source
          </a>
        </div>
      </div>
      <p className="text-muted-foreground mb-6">{projects[currentIndex].description}</p>
      <ProjectDemo project={projects[currentIndex]} />

      <div className="flex items-center justify-center gap-4 mt-6">
        <button
          onClick={goPrev}
          className="p-2 rounded-lg border border-border hover:bg-muted transition-colors"
        >
          <ChevronLeft className="w-5 h-5" />
        </button>
        <div className="flex gap-2">
          {projects.map((_, idx) => (
            <button
              key={idx}
              onClick={() => setCurrentIndex(idx)}
              className={`w-3 h-3 rounded-full transition-colors ${
                idx === currentIndex ? "bg-green-600" : "bg-muted-foreground/30"
              }`}
            />
          ))}
        </div>
        <span className="text-sm text-muted-foreground">
          {currentIndex + 1} / {projects.length}
        </span>
        <button
          onClick={goNext}
          className="p-2 rounded-lg border border-border hover:bg-muted transition-colors"
        >
          <ChevronRight className="w-5 h-5" />
        </button>
      </div>
    </div>
  )
}

export function OpenSourceTabs({ categories }: OpenSourceTabsProps) {
  const [activeTab, setActiveTab] = useState(0)

  return (
    <div className="w-full">
      <div className="flex border-b border-border px-6 overflow-x-auto">
        {categories.map((category, idx) => {
          const Icon = category.icon
          return (
            <button
              key={category.name}
              data-tab={idx}
              onClick={() => setActiveTab(idx)}
              className={`flex items-center gap-2 px-6 py-4 font-medium whitespace-nowrap border-b-2 transition-colors os-tab-button ${
                activeTab === idx
                  ? "border-green-600 text-green-600"
                  : "border-transparent text-muted-foreground hover:text-foreground"
              }`}
            >
              <Icon className={`w-5 h-5 ${activeTab === idx ? category.color : ""}`} />
              {category.name}
              <span className="ml-2 text-xs bg-muted px-2 py-0.5 rounded-full">
                {category.projects.length}
              </span>
            </button>
          )
        })}
      </div>

      <div className="p-6">
        <ProjectCarousel category={categories[activeTab]} />
      </div>
    </div>
  )
}
